<template>
  <div class="Home">
    <div class="bg" :style="{height:bgHeight+'px',width:bgWidth+'px'}">
      <canvas id="canvas" :style="{background:'#111',height:bgHeight+'px',width:bgWidth+'px'}"></canvas>
      <div class="btn">
        <router-link to="/blog/0">点击进入博客</router-link>
      </div>
      <bottomFooter></bottomFooter>
    </div>
  </div>
</template>

<script>
  import bottomFooter from "../../components/bottomFooter";

  export default {
    name: "Home",
    components:{
      bottomFooter
    },
    data(){
      return{
        bgHeight:0,
        bgWidth:0,
        canvasTime:null//canvas动画的定时器
      }
    },
    methods:{
      //获取窗口高度
      getWindowSize(){
        this.bgHeight = window.innerHeight;
        this.bgWidth = window.innerWidth;
      }
    },
    mounted() {
      //在当前页面一直获取窗口高
      this.getWindowSize();
      window.addEventListener("resize",this.getWindowSize);
      //canvas画布
      (()=>{
        //获取画布对象
        var canvas = document.getElementById("canvas");
        //获取画布的上下文
        var context =canvas.getContext("2d");
        //获取浏览器屏幕的宽度和高度
        var W = window.innerWidth;
        var H = window.innerHeight;
        //设置canvas的宽度和高度
        canvas.width = W;
        canvas.height = H;
        //每个文字的字体大小
        var fontSize = 16;
        //计算列
        var colunms = Math.floor(W /fontSize);
        //记录每列文字的y轴坐标
        var drops = [];
        //给每一个文字初始化一个起始点的位置
        for(var i=0;i<colunms;i++){
          drops.push(0);
        }

        //运动的文字
        var str ="javascript html5 canvas";
        //绘画的函数
        function draw(){
          context.fillStyle = "rgba(0,0,0,0.1)";
          context.fillRect(0,0,W,H);
          //给字体设置样式
          context.font = "700 "+fontSize+"px  微软雅黑";
          //给字体添加颜色
          context.fillStyle ="green";//可以rgb,hsl, 标准色，十六进制颜色#00CC33
          //写入画布中
          for(var i=0;i<colunms;i++){
            var index = Math.floor(Math.random() * str.length);
            var x = i*fontSize;
            var y = drops[i] *fontSize;
            context.fillText(str[index],x,y);
            //如果要改变时间，肯定就是改变每次他的起点
            if(y >= canvas.height && Math.random() > 0.99){
              drops[i] = 0;
            }
            drops[i]++;
          }
        };

        draw();
        this.canvasTime = setInterval(draw,30);
      })();
      //
    },
    destroyed() {
      //在离开次页面时删除这个事件
      window.removeEventListener("resize",this.getWindowSize);
      clearInterval(this.canvasTime);
    }
  }
</script>

<style scoped lang="less">
  .Home{
    width: 100%;
    overflow: hidden;
    .bg{
      position: relative;
      overflow: hidden;
      #canvas,.btn{
        position: absolute;
      }
      .btn{
        display: flex;
        flex-wrap: wrap;
        justify-content: center;
        align-items: center;
        width: 100%;
        height: 100%;
        z-index: 1;
        >a{
          display: inline-block;
          height: 45px;
          line-height: 45px;
          padding: 0 18px;
          /*background-color: #001E00;*/
          color: #fff;
          white-space: nowrap;
          text-align: center;
          font-size: 20px;
          border: none;
          border-radius: 5px;
          cursor: pointer;
          transition: opacity .3s;
          &:hover{
            opacity: .8;
          }
        }
      }
      &::before{
        position: absolute;
        content: "";
        width: 100%;
        height: 100%;
        z-index: 1;
        background-color: rgba(0,0,0,.3);
      }
    }
  }
</style>